                        {categories.map((category) => (
                            <button
                                key={category}
                                onClick={() => setActiveCategory(category)}
                                className={`px-6 py-2 rounded-full text-xs font-bold uppercase tracking-widest transition-all duration-300 neo-brutal-sm ${activeCategory === category
                                    ? 'bg-black dark:bg-white text-white dark:text-black'
                                    : 'bg-white dark:bg-black text-gray-500 hover:text-black dark:text-gray-400 dark:hover:text-white'
                                    }`}
                            >
                                {category}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Skills Container */}
                <div className="max-w-5xl mx-auto min-h-[200px]">
                    <div className="flex flex-wrap justify-center gap-4">
                        {filteredSkills.map((skill) => (
                            <motion.div
                                key={skill.name}
                                initial={{ opacity: 0, scale: 0.8 }}
                                animate={{ opacity: 1, scale: 1 }}
                                transition={{ type: 'spring', stiffness: 300, damping: 20 }}
                                className="px-6 py-3 rounded-[1.2rem] bg-white dark:bg-black text-gray-900 dark:text-gray-200 font-bold text-xs transition-all duration-300 cursor-default flex items-center gap-2 group hover:bg-black dark:hover:bg-white hover:text-white dark:hover:text-black neo-brutal-sm"
                            >
                                <skill.icon className="w-4 h-4 text-gray-400 group-hover:text-white dark:group-hover:text-black transition-colors" />
                                {skill.name}
                            </motion.div>
                        ))}
                    </div>
                </div>
            </div>
        </section>
    );
};

export default Skills;
